      __typename
      ... on YoutubeLive {
        title
        description
        publishTime
        embed
        thumbnails {
          url
          height
          width
          __typename
        }
        __typename
      }
    }
  }
}
"}]

[{"operationName":"getMemberStatsHeader","variables":{"id":3073969},"query":"query getMemberStatsHeader($id: Int!) {
  member(id: $id) {
    id
    firstName
    lastName
    initials
    aliases(includeInactive: true) {
      id
      displayName
      memberNumber
      league {
        id
        slug
        name
        isDefault
        number
        __typename
      }
      formats
      stats {
        __typename
        skillLevel
        CLA
      }
      __typename
    }
    __typename
  }
}
"},{"operationName":"FormatsByMemberId","variables":{"withMember":false,"withAlias":true,"aliasId":2768882,"memberId":3073969},"query":"query FormatsByMemberId($memberId: Int!, $withMember: Boolean!, $withAlias: Boolean!, $aliasId: Int!) {
  alias(id: $aliasId) @include(if: $withAlias) {
    id
    formats
    league {
      id
      slug
      isDefault
      __typename
    }
    __typename
  }
  member(id: $memberId) @include(if: $withMember) {
    id
    ... on Member {
      aliases {
        id
        formats
        league {
          id
          slug
          isDefault
          __typename
        }
        __typename
      }
      __typename
    }
    __typename
  }
}
"}]
